document.querySelectorAll(".accordion button").forEach(e=>{e.addEventListener("click",()=>{const t=e.closest(".accordion"),o=t?.classList.contains("open");if(document.querySelectorAll(".accordion").forEach(e=>{e.classList.remove("open"),e.querySelector("button")?.setAttribute("aria-expanded","false");const t=e.querySelector("button b");t&&(t.textContent="+")}),t&&!o){t.classList.add("open"),e.setAttribute("aria-expanded","true");const o=e.querySelector("b");o&&(o.textContent="−")}})});